+    let (baseline_loss, high_support_loss, mut block_schur_loss) = policy_losses(features, n_cols);
+    if features.budget_exhausted {
+        return DecoderPolicyDecision {
+            mode: DecoderPolicyMode::ConservativeBaseline,
+            features,
+            baseline_loss,
+            high_support_loss,
+            block_schur_loss,
