+
+    let hard_gate = n_cols >= HARD_REGIME_MIN_COLS
+        && (features.density_permille >= HARD_REGIME_DENSITY_PERCENT.saturating_mul(10)
+            || n_rows <= n_cols.saturating_add(HARD_REGIME_NEAR_SQUARE_EXTRA_ROWS));
+    if !hard_gate {
